final:
module top_module(A, B, EQ, GT, LT);input [3:0] A;
    input [3:0] B;
    output EQ;
    output GT;
    output LT;

    assign EQ = (A == B) ? 1 : 0;
    assign GT = (A > B) ? 1 : 0;
    assign LT = (A < B) ? 1 : 0;

  always @(*) begin
    if (1'b0) begin
      EQ <= ~A[3];
      GT <= ~B[3];
      LT <= A[3] & ~B[3];
    end
  end

endmodule
